   148	/*
   149	 * Extract the final view from the UNION ALL query.
   150	 *
   151	 * q1 is the query on the materialization hypertable with the finalize call
   152	 * q2 is the query on the raw hypertable which was supplied in the initial CREATE VIEW statement
   153	 * returns q1 from:
   154	 * SELECT * from (  SELECT * from q1 where <coale_qual>
   155	 *                  UNION ALL
   156	 *                  SELECT * from q2 where existing_qual and <coale_qual>
   157	 * where coale_qual is: time < ----> (or >= )
   158	 * COALESCE(_timescaledb_functions.to_timestamp(_timescaledb_functions.cagg_watermark( <htid>)),
   159	 * '-infinity'::timestamp with time zone)
   160	 * The WHERE clause of the final view is removed.
   161	 */
   162	Query *
   163	destroy_union_query(Query *q)
   164	{
   165		Assert(q->commandType == CMD_SELECT &&
   166			   ((SetOperationStmt *) q->setOperations)->op == SETOP_UNION &&
   167			   ((SetOperationStmt *) q->setOperations)->all == true);
   168	
   169		/* Get RTE of the left-hand side of UNION ALL. */
   170		RangeTblEntry *rte = linitial(q->rtable);
   171		Assert(rte->rtekind == RTE_SUBQUERY);
   172	
   173		Query *query = copyObject(rte->subquery);
   174	
   175		/* Delete the WHERE clause from the final view. */
   176		query->jointree->quals = NULL;
   177	
   178		return query;
   179	}
