   184	static void
   185	process_additional_timebucket_parameter(ContinuousAggBucketFunction *bf, Const *arg,
   186											bool *custom_origin)
   187	{
   188		char *tz_name;
   189		switch (exprType((Node *) arg))
   190		{
   191			/* Timezone as text */
   192			case TEXTOID:
   193				tz_name = TextDatumGetCString(arg->constvalue);
   194				if (!ts_is_valid_timezone_name(tz_name))
   195				{
   196					ereport(ERROR,
