   198							 errmsg("invalid timezone name \"%s\"", tz_name)));
   199				}
   200	
   201				bf->bucket_time_timezone = tz_name;
   202				break;
   203			case INTERVALOID:
   204				/* Bucket offset as interval */
   205				bf->bucket_time_offset = DatumGetIntervalP(arg->constvalue);
   206				break;
   207			case DATEOID:
   208				/* Bucket origin as Date */
   209				if (!arg->constisnull)
   210					bf->bucket_time_origin =
   211						date2timestamptz_opt_overflow(DatumGetDateADT(arg->constvalue), NULL);
   212				*custom_origin = true;
   213				break;
   214			case TIMESTAMPOID:
   215				/* Bucket origin as Timestamp */
   216				bf->bucket_time_origin = DatumGetTimestamp(arg->constvalue);
   217				*custom_origin = true;
   218				break;
   219			case TIMESTAMPTZOID:
   220				/* Bucket origin as TimestampTZ */
   221				bf->bucket_time_origin = DatumGetTimestampTz(arg->constvalue);
   222				*custom_origin = true;
   223				break;
   224			case INT2OID:
   225				/* Bucket offset as smallint */
   226				bf->bucket_integer_offset = DatumGetInt16(arg->constvalue);
   227				break;
   228			case INT4OID:
   229				/* Bucket offset as int */
   230				bf->bucket_integer_offset = DatumGetInt32(arg->constvalue);
   231				break;
   232			case INT8OID:
   233				/* Bucket offset as bigint */
   234				bf->bucket_integer_offset = DatumGetInt64(arg->constvalue);
   235				break;
   236			default:
   237				ereport(ERROR,
   238						(errcode(ERRCODE_TS_INTERNAL_ERROR),
   239						 errmsg("unable to handle time_bucket parameter of type: %s",
