   279		 * or `origin`.
   280		 *
   281		 * Time bucket function variations with 3 and 5 arguments:
   282		 *   - time_bucket(width SMALLINT, ts SMALLINT,    offset SMALLINT)
   283		 *   - time_bucket(width INTEGER,  ts INTEGER,     offset INTEGER)
   284		 *   - time_bucket(width BIGINT,   ts BIGINT,      offset BIGINT)
   285		 *   - time_bucket(width INTERVAL, ts DATE,        offset INTERVAL)
   286		 *   - time_bucket(width INTERVAL, ts DATE,        origin DATE)
   287		 *   - time_bucket(width INTERVAL, ts TIMESTAMPTZ, offset INTERVAL)
   288		 *   - time_bucket(width INTERVAL, ts TIMESTAMPTZ, origin TIMESTAMPTZ)
   289		 *   - time_bucket(width INTERVAL, ts TIMESTAMPTZ, timezone TEXT, origin TIMESTAMPTZ,
   290		 *                 offset INTERVAL)
   291		 *   - time_bucket(width INTERVAL, ts TIMESTAMP,   offset INTERVAL)
   292		 *   - time_bucket(width INTERVAL, ts TIMESTAMP,   origin TIMESTAMP)
   293		 */
   294		if (nargs >= 3)
   295		{
   296			Const *arg = check_time_bucket_argument(lthird(fe->args), "third", process_checks);
   297			process_additional_timebucket_parameter(bf, arg, &custom_origin);
