   537	/*
   538	 * Expand an invalidation to bucket boundaries.
   539	 *
   540	 * Since a refresh always materializes full buckets, we can safely expand an
   541	 * invalidation to bucket boundaries and in the process merge a lot more
   542	 * invalidations.
   543	 */
   544	void
   545	invalidation_expand_to_bucket_boundaries(Invalidation *inv, Oid time_type_oid,
   546											 const ContinuousAggBucketFunction *bucket_function)
   547	{
   548		const int64 time_dimension_min = ts_time_get_min(time_type_oid);
   549		const int64 time_dimension_max = ts_time_get_max(time_type_oid);
   550		int64 min_bucket_start;
   551		int64 max_bucket_end;
   552	
   553		if (bucket_function->bucket_fixed_interval == false)
   554		{
   555			ts_compute_circumscribed_bucketed_refresh_window_variable(&inv->lowest_modified_value,
   556																	  &inv->greatest_modified_value,
   557																	  bucket_function);
   558			return;
   559		}
   560	
   561		int64 bucket_width = ts_continuous_agg_fixed_bucket_width(bucket_function);
   562		Assert(bucket_width > 0);
   563	
   564		/* Compute the start of the "first" bucket for the type. The min value
   565		 * must be at the start of the "first" bucket or somewhere in the
   566		 * bucket. If the min value falls on the exact start of the bucket we are
   567		 * good. Otherwise, we need to move to the next full bucket. */
   568		min_bucket_start = ts_time_saturating_add(time_dimension_min, bucket_width - 1, time_type_oid);
   569		min_bucket_start = ts_time_bucket_by_type(bucket_width, min_bucket_start, time_type_oid);
   570	
   571		/* Compute the end of the "last" bucket for the time type. Remember that
   572		 * invalidations are inclusive, so the "greatest" value should be the last
   573		 * value of the last full bucket. Either the max value is already the last
   574		 * value of the last bucket, or we need to return the last value of the
   575		 * previous full bucket.  */
   576		max_bucket_end = ts_time_bucket_by_type(bucket_width, time_dimension_max, time_type_oid);
   577	
   578		/* Check if the max value was already the last value of the last bucket */
   579		if (ts_time_saturating_add(max_bucket_end, bucket_width - 1, time_type_oid) ==
   580			time_dimension_max)
   581		{
   582			max_bucket_end = time_dimension_max;
   583		}
   584		else
   585		{
   586			/* The last bucket was partial. To get the end of previous bucket, we
   587			 * need to move one step down from the partial last bucket. */
   588			max_bucket_end = ts_time_saturating_sub(max_bucket_end, 1, time_type_oid);
   589		}
   590	
   591		if (inv->lowest_modified_value < min_bucket_start)
   592			/* Below the min bucket, so treat as invalid to -infinity. */
   593			inv->lowest_modified_value = INVAL_NEG_INFINITY;
   594		else if (inv->lowest_modified_value > max_bucket_end)
   595			/* Above the max bucket, so treat as invalid to +infinity. */
   596			inv->lowest_modified_value = INVAL_POS_INFINITY;
   597		else
   598			inv->lowest_modified_value =
   599				ts_time_bucket_by_type(bucket_width, inv->lowest_modified_value, time_type_oid);
   600	
   601		if (inv->greatest_modified_value < min_bucket_start)
   602			/* Below the min bucket, so treat as invalid to -infinity. */
   603			inv->greatest_modified_value = INVAL_NEG_INFINITY;
   604		else if (inv->greatest_modified_value > max_bucket_end)
   605			/* Above the max bucket, so treat as invalid to +infinity. */
   606			inv->greatest_modified_value = INVAL_POS_INFINITY;
   607		else
   608		{
   609			inv->greatest_modified_value =
   610				ts_time_bucket_by_type(bucket_width, inv->greatest_modified_value, time_type_oid);
   611			inv->greatest_modified_value =
   612				ts_time_saturating_add(inv->greatest_modified_value, bucket_width - 1, time_type_oid);
   613		}
   614	}
